#[extendr]
pub fn new_llmusage(
    model: Option<String>,
    source: Option<String>,
    input_tokens: Option<f64>,
    output_tokens: Option<f64>,
    total_tokens: Option<f64>,
    estimated_cost: Option<f64>,
    finish_reason: Option<String>,
) -> LlmUsage {
    let mut __out = <LlmUsage>::default();
    if let Some(v) = model {
        __out.model = v;
    }
    if let Some(v) = source {
        __out.source = v;
    }
    if let Some(v) = input_tokens {
        __out.input_tokens = Some(v);
    }
    if let Some(v) = output_tokens {
        __out.output_tokens = Some(v);
    }
    if let Some(v) = total_tokens {
        __out.total_tokens = Some(v);
    }
    if let Some(v) = estimated_cost {
        __out.estimated_cost = Some(v);
    }
    if let Some(v) = finish_reason {
        __out.finish_reason = Some(v);
    }
    __out
}

