#[extendr]
impl Metadata {
    pub fn is_empty(&self) -> bool {
        let core_self = kreuzberg::Metadata {
            title: self.title.clone(),

            subject: self.subject.clone(),

            authors: self.authors.clone(),

            keywords: self.keywords.clone(),

            language: self.language.clone(),

            created_at: self.created_at.clone(),

            modified_at: self.modified_at.clone(),

            created_by: self.created_by.clone(),

            modified_by: self.modified_by.clone(),

            pages: self.pages.clone().map(Into::into),

            format: Default::default(),
            image_preprocessing: self.image_preprocessing.clone().map(Into::into),

            json_schema: self.json_schema.as_ref().and_then(|s| serde_json::from_str(s).ok()),

            error: self.error.clone().map(Into::into),

            extraction_duration_ms: self.extraction_duration_ms.map(|v| v as u64),

            category: self.category.clone(),

            tags: self.tags.clone(),

            document_version: self.document_version.clone(),

            abstract_text: self.abstract_text.clone(),

            output_format: self.output_format.clone(),

            ocr_used: self.ocr_used,

            additional: self
                .additional
                .clone()
                .into_iter()
                .map(|(k, v)| {
                    (
                        k.into(),
                        serde_json::from_str(&v).unwrap_or(serde_json::Value::String(v)),
                    )
                })
                .collect(),
        };
        core_self.is_empty()
    }
}

